import React from "react";
import { Dumbbell, Plus } from "lucide-react";

export function WorkoutsPage() {
  return (
    <div className="space-y-6 animate-in fade-in duration-500">

      {/* Cabecera */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white tracking-tight">Entrenamientos</h1>
          <p className="text-gray-400 mt-1">Biblioteca de rutinas y ejercicios del gimnasio.</p>
        </div>
        <button className="bg-[#E31C25] text-white px-6 py-3 rounded-xl font-bold hover:bg-[#A6151B] transition-all flex items-center gap-2 shadow-[0_0_15px_rgba(227,28,37,0.3)] shrink-0">
          <Plus size={20} /> Añadir Ejercicio
        </button>
      </div>

      {/* Contenedor Vacío / Placeholder */}
      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-2xl p-20 flex flex-col items-center text-center shadow-xl">
        <div className="w-24 h-24 bg-[#E31C25]/5 rounded-full flex items-center justify-center mb-6 border border-[#E31C25]/10">
          <Dumbbell className="w-12 h-12 text-[#E31C25] opacity-80" />
        </div>
        <h2 className="text-2xl font-bold text-white mb-2">Biblioteca de Ejercicios</h2>
        <p className="text-gray-400 max-w-sm mx-auto">
          Gestiona los programas de entrenamiento, añade nuevos ejercicios y asigna rutinas a tus atletas desde aquí.
        </p>
      </div>

    </div>
  );
}
